import { LibraryVariant } from "../model/types";
import { renderSelectionCard } from "../shared/render-content-cards";
import {
  renderCallout,
  renderPersonListItem,
  renderStatTile,
  renderStatusChip,
  renderTabStrip
} from "../shared/render-display-primitives";
import { renderButton, renderTextInput } from "../shared/render-controls";

function componentCard(title: string, subtitle: string, toneClass?: string): string {
  return renderSelectionCard({
    title,
    badge: { label: toneClass === "warning" ? "alert" : "summary", toneClass: toneClass === "warning" ? "target-attention" : "target-ready" },
    lines: [{ text: subtitle }],
    className: `selection-card ${toneClass ?? ""}`.trim()
  });
}

export function renderComponent(id: string, variant: LibraryVariant): string {
  const changed = variant === "v2";

  switch (id) {
    case "component-button-primary":
      return `<div class="row">${renderButton({ label: changed ? "Launch" : "Save", className: changed ? "accent-strong" : "accent" })}</div>`;
    case "component-button-secondary":
      return `<div class="row">${renderButton({ label: changed ? "Back" : "Cancel" })}</div>`;
    case "component-button-danger":
      return `<div class="row">${renderButton({ label: "Delete Campaign", className: "danger" })}</div>`;
    case "component-card-highlight":
      return componentCard(changed ? "Alert Card" : "Highlight Card", "Priority signal for operators", changed ? "warning" : "accent");
    case "component-card-compact":
      return componentCard("Compact Card", "Small summary payload for dashboard rails");
    case "component-banner-info":
      return renderCallout({ title: changed ? "Migration Window Open" : "Information", description: "All write paths are healthy." });
    case "component-banner-warning":
      return renderCallout({ title: "Warning", description: "One connector is running in degraded mode.", borderColorVar: "--warning" });
    case "component-modal-shell":
      return `<div class="tile"><h3>Confirm Change</h3><div class="muted">This action will update all placements.</div><div class="row">${renderButton({ label: "Cancel" })}${renderButton({ label: "Confirm", className: "accent" })}</div></div>`;
    case "component-table-row":
      return `<table class="table"><thead><tr><th>Name</th><th>Status</th><th>Spend</th></tr></thead><tbody><tr><td>Launch-Alpha</td><td>${renderStatusChip({ label: "Active", className: "success" })}</td><td>$12,320</td></tr></tbody></table>`;
    case "component-search-bar":
      return `<div class="row">${renderTextInput({ className: "input-field", value: "Search campaigns" })}${renderButton({ label: "Search", className: "accent" })}${renderButton({ label: "Filters" })}</div>`;
    case "component-stat-tile":
      return renderStatTile({ value: changed ? "$1.34M" : "$1.20M", label: "Projected Quarterly Revenue" });
    case "component-nav-tabs":
      return renderTabStrip({ tabs: ["Overview", "Audiences", "Rules", "History"], activeTab: "Overview" });
    case "component-toast-success":
      return renderSelectionCard({
        title: "Saved",
        badge: { label: "success", toneClass: "target-ready" },
        lines: [{ text: "Your changes were applied." }],
        className: "selection-card success"
      });
    case "component-toast-error":
      return renderSelectionCard({
        title: "Deploy Failed",
        badge: { label: "error", toneClass: "target-attention" },
        lines: [{ text: "Check build logs and retry." }],
        className: "selection-card danger"
      });
    case "component-form-section":
      return `<div class="tile layout-stack"><div><strong>Campaign Name</strong><div class="row">${renderTextInput({ className: "input-field", value: "Spring-Launch" })}</div></div><div><strong>Budget</strong><div class="row">${renderTextInput({ className: "input-field", value: "$8,000" })}</div></div><div class="row">${renderButton({ label: "Save", className: "accent" })}${renderButton({ label: "Discard" })}</div></div>`;
    case "component-user-list-item":
      return renderPersonListItem({ initials: "AL", title: "Avery Lane", subtitle: "Role: Admin", statusLabel: "Online" });
    case "component-activity-timeline":
      return `<div class="tile"><details><summary><strong>Activity Timeline</strong></summary><div class="muted">No recent activity.</div></details></div>`;
    default:
      return `<div class="tile">Unknown component</div>`;
  }
}

import { renderComponent } from "../components/render-component";
import { renderPage } from "../pages/render-page";
import { renderPrimitive } from "../primitives/render-primitive";
import { SurfaceDefinition, LibraryVariant } from "../model/types";
import { renderSurfaceFrame } from "./render-surface-frame";
import { renderView } from "../views/render-view";

function renderBody(definition: SurfaceDefinition, variant: LibraryVariant): string {
  const effectiveVariant: LibraryVariant = definition.changesInV2 ? variant : "v1";

  if (definition.layer === "primitive") {
    return renderPrimitive(definition.id, effectiveVariant);
  }

  if (definition.layer === "component") {
    return renderComponent(definition.id, effectiveVariant);
  }

  if (definition.layer === "view") {
    return renderView(definition.id, effectiveVariant);
  }

  return renderPage(definition.id, effectiveVariant);
}

export function renderSurfacePage(definition: SurfaceDefinition, variant: LibraryVariant): string {
  const body = renderBody(definition, variant);
  return `<!doctype html><html><head><meta charset="utf-8" /><title>${definition.title}</title></head><body><div class="page">${renderSurfaceFrame({ title: definition.title, testId: definition.testId, layer: definition.layer, body, variant })}</div></body></html>`;
}

export function renderSurfaceCatalogIndex(catalog: SurfaceDefinition[], variant: LibraryVariant): string {
  const groups = ["primitive", "component", "view", "page"] as const;
  const sections = groups
    .map((group) => {
      const items = catalog
        .filter((item) => item.layer === group)
        .map((item) => `<li><a href="/library/${item.id}?variant=${variant}">${item.title}</a></li>`)
        .join("");
      return `<section><h2>${group}</h2><ul>${items}</ul></section>`;
    })
    .join("");

  return `<!doctype html><html><head><meta charset="utf-8" /><title>Surface Catalog</title><style>body{font-family:Segoe UI,Helvetica Neue,sans-serif;padding:24px;background:#f2f6fc;color:#223449}section{background:#fff;border:1px solid #c4d0df;border-radius:12px;padding:16px;margin-bottom:14px}a{color:#1f5ea7;text-decoration:none}li{margin:6px 0}.toolbar{display:flex;gap:12px;align-items:center;margin-bottom:20px;padding:14px 16px;background:#fff;border:1px solid #c4d0df;border-radius:12px}.toolbar strong{font-size:14px}</style></head><body><h1>Primitive/Component/View/Page Catalog</h1><div class="toolbar"><strong>Variant:</strong><a href="/library?variant=v1">v1</a><a href="/library?variant=v2">v2</a></div>${sections}</body></html>`;
}

import { renderComponent } from "../components/render-component";
import { LibraryVariant } from "../model/types";
import { renderSelectionCard } from "../shared/render-content-cards";
import { renderChecklistRow, renderStatTile } from "../shared/render-display-primitives";
import { renderGridRow, renderGridThree, renderList, renderRow, renderSectionHeader, renderStack } from "../shared/render-layout";

export function renderView(id: string, variant: LibraryVariant): string {
  const changed = variant === "v2";

  switch (id) {
    case "view-dashboard-summary":
      return renderStack([
        renderSelectionCard({ title: changed ? "Revenue Operations" : "Growth Operations", badge: { label: "overview", toneClass: "target-ready" }, lines: [{ text: "Dashboard summary" }] }),
        renderGridRow([renderComponent("component-stat-tile", variant), renderComponent("component-card-highlight", variant)]),
        renderComponent("component-banner-info", variant)
      ]);
    case "view-list-overview":
      return renderStack([
        renderList([
          renderComponent("component-user-list-item", variant),
          renderComponent("component-user-list-item", variant),
          renderComponent("component-user-list-item", variant)
        ])
      ]);
    case "view-settings-panel":
      return renderStack([
        renderComponent("component-form-section", variant),
        renderRow([
          renderComponent("component-button-primary", variant),
          renderComponent("component-button-secondary", variant),
          renderComponent("component-button-danger", variant)
        ])
      ]);
    case "view-empty-results":
      return renderSectionHeader({
        title: "No placements found",
        subtitle: "Try broadening your filters.",
        bodyHtml: renderRow([renderComponent("component-button-primary", variant), renderComponent("component-search-bar", variant)])
      });
    case "view-campaign-table":
      return renderStack([
        renderComponent("component-nav-tabs", variant),
        renderComponent("component-table-row", variant),
        renderComponent("component-table-row", variant)
      ]);
    case "view-notifications-center":
      return renderStack([
        renderComponent("component-toast-success", variant),
        renderComponent("component-toast-error", variant),
        renderComponent("component-banner-warning", variant)
      ]);
    case "view-user-directory":
      return renderStack([
        renderComponent("component-search-bar", variant),
        renderList([
          renderComponent("component-user-list-item", variant),
          renderComponent("component-user-list-item", variant),
          renderComponent("component-user-list-item", variant)
        ])
      ]);
    case "view-revenue-kpis":
      return renderGridThree([
        renderComponent("component-stat-tile", variant),
        renderComponent("component-stat-tile", variant),
        renderComponent("component-stat-tile", variant)
      ]);
    case "view-onboarding-checklist":
      return renderStack([
        renderSelectionCard({ title: "Onboarding", badge: { label: "checklist", toneClass: "target-ready" }, lines: [{ text: "Complete these tasks for launch readiness." }] }),
        renderList([
          renderChecklistRow({ statusLabel: "done", statusClassName: "success", text: "Connect data feed" }),
          renderChecklistRow({ statusLabel: "pending", statusClassName: "warning", text: "Define budget guardrails" }),
          renderChecklistRow({ statusLabel: "pending", statusClassName: "warning", text: "Enable alert notifications" })
        ])
      ]);
    case "view-approval-queue":
      return renderStack([
        renderComponent("component-card-compact", variant),
        renderComponent("component-card-compact", variant),
        renderComponent("component-modal-shell", variant)
      ]);
    case "view-audit-log":
      return renderStack([
        renderSelectionCard({ title: "Audit Log", badge: { label: "recent", toneClass: "target-ready" }, lines: [{ text: "Recent critical events" }] }),
        '<table class="table"><thead><tr><th>Time</th><th>Actor</th><th>Event</th></tr></thead><tbody><tr><td>09:41</td><td>system</td><td>Theme updated</td></tr><tr><td>09:43</td><td>andre</td><td>Campaign budget modified</td></tr><tr><td>09:46</td><td>agent</td><td>Intent run completed</td></tr></tbody></table>'
      ]);
    case "view-billing-overview":
      return renderStack([
        renderGridRow([
          renderStatTile({ value: "$248,330", label: "Month to Date" }),
          renderStatTile({ value: "$19,882", label: "Outstanding" })
        ]),
        renderComponent("component-banner-info", variant)
      ]);
    default:
      return `<div class="tile">Unknown view</div>`;
  }
}

import { LibraryVariant } from "../model/types";
import { renderButton, renderTextInput } from "../shared/render-controls";

export function renderInputField(value: string): string {
  return renderTextInput({ className: "input-field", value });
}

export function renderPrimitive(id: string, variant: LibraryVariant): string {
  const changed = variant === "v2";

  switch (id) {
    case "primitive-color-chip":
      return `<div class="row"><span class="chip">neutral</span><span class="chip accent">accent</span><span class="chip success">success</span><span class="chip warning">warning</span></div>`;
    case "primitive-typography":
      return `<div><h2>${changed ? "Narrative Heading" : "Heading Example"}</h2><p>Body copy for typography testing.</p><div class="muted">caption text</div></div>`;
    case "primitive-pill-tag":
      return `<div class="row"><span class="chip">alpha</span><span class="chip">beta</span><span class="chip">stable</span></div>`;
    case "primitive-input-field":
      return `<div class="row">${renderInputField("Search users")}${renderButton({ label: "Find", className: "accent" })}${renderButton({ label: "Clear" })}</div>`;
    case "primitive-button-set":
      return `<div class="row">${renderButton({ label: "Primary", className: "accent" })}${renderButton({ label: "Secondary" })}${renderButton({ label: "Danger", className: "danger" })}</div>`;
    case "primitive-avatar-stack":
      return `<div class="avatar-stack"><span class="avatar">AA</span><span class="avatar">BM</span><span class="avatar">CH</span><span class="avatar">DK</span></div>`;
    case "primitive-status-indicator":
      return `<div class="row"><span class="chip success">Healthy</span><span class="chip warning">Degraded</span><span class="chip danger">Critical</span></div>`;
    case "primitive-spacing-scale":
      return `<div class="layout-stack"><div class="tile" style="padding:8px">space-sm</div><div class="tile" style="padding:14px">space-md</div><div class="tile" style="padding:22px">space-lg</div></div>`;
    case "primitive-icon-list":
      return `<div class="row"><span class="chip">i</span><span class="chip">?</span><span class="chip">!</span><span class="chip">*</span></div>`;
    case "primitive-kpi-block":
      return `<div class="layout-row"><div class="tile stat"><strong>${changed ? "19.2%" : "18.4%"}</strong><div class="muted">Conversion</div></div><div class="tile stat"><strong>4m 21s</strong><div class="muted">Avg Session</div></div></div>`;
    default:
      return `<div class="tile">Unknown primitive</div>`;
  }
}
